#include <stdio.h>
#include <stdlib.h>

int main() {
    int T, N, M, X[1000], Y[1000], i, j, k, count;
    int board[1000][1000];

    scanf("%d", &T);
    while (T--) {
        scanf("%d %d", &N, &M);
        for (i = 0; i < N; i++) {
            for (j = 0; j < N; j++) {
                board[i][j] = 0;
            }
        }
        for (i = 0; i < M; i++) {
            scanf("%d %d", &X[i], &Y[i]);
            X[i]--; Y[i]--;
            board[X[i]][Y[i]] = 1;
        }
        count = 0;
        for (i = 0; i < N; i++) {
            for (j = 0; j < N; j++) {
                if (board[i][j] == 0) {
                    int forked = 0;
                    for (k = 0; k < M; k++) {
                        if (abs(X[k] - i) == 2 && abs(Y[k] - j) == 1) forked++;
                        if (abs(X[k] - i) == 1 && abs(Y[k] - j) == 2) forked++;
                    }
                    if (forked >= 2) count++;
                }
            }
        }
        printf("%d\n", count);
    }
    return 0;
}

