public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            int M = sc.nextInt();
            int[][] board = new int[N][N];
            int[] X = new int[M];
            int[] Y = new int[M];
            for (int i = 0; i < M; i++) {
                X[i] = sc.nextInt() - 1;
                Y[i] = sc.nextInt() - 1;
                board[X[i]][Y[i]] = 1;
            }
            int count = 0;
            for (int i = 0; i < N; i++) {
                for (int j = 0; j < N; j++) {
                    if (board[i][j] == 0) {
                        int forked = 0;
                        for (int k = 0; k < M; k++) {
                            if (Math.abs(X[k] - i) == 2 && Math.abs(Y[k] - j) == 1) forked++;
                            if (Math.abs(X[k] - i) == 1 && Math.abs(Y[k] - j) == 2) forked++;
                        }
                        if (forked >= 2) count++;
                    }
                }
            }
            System.out.println(count);
        }
    }
}

